import React from 'react';

function About() {
  return (
    <div style={containerStyle}>
      {/* 1. Hero Header Section */}
      <section style={heroSection}>
        <h1 style={titleStyle}>About <span>GigNexus</span></h1>
        <p style={subtitleStyle}>Empowering Students, Bridging Opportunities.</p>
      </section>

      {/* 2. Mission and Vision Cards */}
      <section style={contentSection}>
        <div style={cardStyle}>
          <h2 style={cardTitle}>Our Mission</h2>
          <p style={cardText}>
            GigNexus is a dedicated marketplace designed exclusively for students. 
            Our mission is to provide students with a platform to showcase their 
            talents, gain professional experience, and achieve financial independence 
            while managing their studies.
          </p>
        </div>

        <div style={cardStyle}>
          <h2 style={cardTitle}>Why GigNexus?</h2>
          <ul style={listStyle}>
            <li><strong>For Students:</strong> Find flexible work that fits your academic schedule.</li>
            <li><strong>For Clients:</strong> Access high-quality talent at student-friendly prices.</li>
            <li><strong>For Growth:</strong> Build a professional portfolio before you even graduate.</li>
          </ul>
        </div>
      </section>

      {/* 3. Core Services/Skills Grid */}
      <section style={{ marginTop: '50px' }}>
        <h2 style={{ textAlign: 'center', color: '#1e293b', marginBottom: '30px' }}>Our Expertise</h2>
        <div style={gridStyle}>
          <div style={skillBox}>💻 Web Development</div>
          <div style={skillBox}>🎨 Graphic Design</div>
          <div style={skillBox}>✍️ Content Writing</div>
          <div style={skillBox}>📱 App Development</div>
          <div style={skillBox}>📊 Digital Marketing</div>
          <div style={skillBox}>🎥 Video Editing</div>
        </div>
      </section>

      {/* 4. Contact Teaser */}
      <section style={footerTeaser}>
        <h3>Have questions?</h3>
        <p>We are here to help you kickstart your freelancing journey.</p>
      </section>
    </div>
  );
}

// --- Professional CSS-in-JS Styles ---
const containerStyle = {
  maxWidth: '1100px',
  margin: '0 auto',
  padding: '60px 20px',
  fontFamily: "'Poppins', sans-serif",
  color: '#334155'
};

const heroSection = {
  textAlign: 'center',
  padding: '80px 20px',
  background: 'linear-gradient(135deg, #1e293b 0%, #334155 100%)',
  color: 'white',
  borderRadius: '30px',
  marginBottom: '50px',
  boxShadow: '0 20px 40px rgba(0,0,0,0.1)'
};

const titleStyle = { 
  fontSize: '3rem', 
  margin: '0',
  fontWeight: '700'
};

const subtitleStyle = { 
  fontSize: '1.2rem', 
  opacity: '0.9', 
  marginTop: '15px' 
};

const contentSection = {
  display: 'grid',
  gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))',
  gap: '30px'
};

const cardStyle = {
  background: 'white',
  padding: '40px',
  borderRadius: '20px',
  boxShadow: '0 10px 25px rgba(0,0,0,0.03)',
  border: '1px solid #f1f5f9',
  textAlign: 'left'
};

const cardTitle = {
  color: '#1e293b',
  marginBottom: '20px',
  fontSize: '1.5rem',
  borderBottom: '3px solid #38bdf8',
  display: 'inline-block',
  paddingBottom: '5px'
};

const cardText = {
  lineHeight: '1.8',
  fontSize: '1rem',
  color: '#64748b'
};

const listStyle = {
  padding: '0',
  listStyle: 'none',
  lineHeight: '2',
  color: '#64748b'
};

const gridStyle = {
  display: 'grid',
  gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))',
  gap: '20px'
};

const skillBox = {
  background: '#f8fafc',
  padding: '25px',
  borderRadius: '15px',
  textAlign: 'center',
  fontWeight: '600',
  color: '#1e293b',
  border: '1px solid #e2e8f0',
  transition: 'transform 0.3s ease'
};

const footerTeaser = {
  marginTop: '80px',
  textAlign: 'center',
  padding: '40px',
  background: '#f1f5f9',
  borderRadius: '20px'
};

export default About;
